import { useState, useEffect, useRef, useCallback } from "react";

const IMG = {
  tapa: "data:image/jpeg;base64,",
  arg1978: "data:image/jpeg;base64,",
  esp1982: "data:image/jpeg;base64,",
  mex1986: "data:image/jpeg;base64,",
  ita1990: "data:image/jpeg;base64,",
  usa1994: "data:image/jpeg;base64,",
  fra1998: "data:image/jpeg;base64,",
  kor2002: "data:image/jpeg;base64,",
  ale2006: "data:image/jpeg;base64,",
  saf2010: "data:image/jpeg;base64,",
  bra2014: "data:image/jpeg;base64,",
  qat2022: "data:image/jpeg;base64,",
};

const PAGES = [
  { key:"arg1978", year:1978, host:"Argentina",    champ:"Argentina", flag:"🇦🇷", color:"#54a0ff" },
  { key:"esp1982", year:1982, host:"España",        champ:"Italia",    flag:"🇮🇹", color:"#ff6b6b" },
  { key:"mex1986", year:1986, host:"México",        champ:"Argentina", flag:"🇦🇷", color:"#54a0ff" },
  { key:"ita1990", year:1990, host:"Italia",        champ:"Alemania",  flag:"🇩🇪", color:"#a29bfe" },
  { key:"usa1994", year:1994, host:"EEUU",          champ:"Brasil",    flag:"🇧🇷", color:"#ffd32a" },
  { key:"fra1998", year:1998, host:"Francia",       champ:"Francia",   flag:"🇫🇷", color:"#5f27cd" },
  { key:"kor2002", year:2002, host:"Corea / Japón", champ:"Brasil",    flag:"🇧🇷", color:"#ffd32a" },
  { key:"ale2006", year:2006, host:"Alemania",      champ:"Italia",    flag:"🇮🇹", color:"#ff6b6b" },
  { key:"saf2010", year:2010, host:"Sudáfrica",     champ:"España",    flag:"🇪🇸", color:"#e17055" },
  { key:"bra2014", year:2014, host:"Brasil",        champ:"Alemania",  flag:"🇩🇪", color:"#00d2d3" },
  { key:"qat2022", year:2022, host:"Qatar",         champ:"Argentina", flag:"🇦🇷", color:"#54a0ff" },
];

// Confetti
function Confetti({ active, color }) {
  const ref = useRef(null);
  const raf = useRef(null);
  useEffect(() => {
    if (!active || !ref.current) return;
    const c = ref.current;
    c.width = c.offsetWidth; c.height = c.offsetHeight;
    const ctx = c.getContext("2d");
    const COLS = ["#54a0ff","#ffd32a","#ffffff","#ff6b6b","#a29bfe","#55efc4","#fd79a8"];
    const pts = Array.from({length:100},()=>({
      x: Math.random()*c.width, y:-10-Math.random()*50,
      vx:(Math.random()-.5)*4, vy:2+Math.random()*4,
      g:0.05+Math.random()*0.04,
      w:5+Math.random()*9, h:3+Math.random()*4,
      col:COLS[Math.floor(Math.random()*COLS.length)],
      a:Math.random()*Math.PI*2, s:(Math.random()-.5)*0.15,
    }));
    const draw = () => {
      ctx.clearRect(0,0,c.width,c.height);
      let alive=false;
      pts.forEach(p=>{
        if(p.y>c.height+20)return; alive=true;
        p.x+=p.vx; p.y+=p.vy; p.vy+=p.g; p.a+=p.s;
        const alpha=Math.max(0,1-p.y/c.height);
        ctx.save();ctx.translate(p.x,p.y);ctx.rotate(p.a);
        ctx.globalAlpha=alpha; ctx.fillStyle=p.col;
        ctx.fillRect(-p.w/2,-p.h/2,p.w,p.h);
        ctx.restore();
      });
      if(alive) raf.current=requestAnimationFrame(draw);
    };
    raf.current=requestAnimationFrame(draw);
    return ()=>cancelAnimationFrame(raf.current);
  },[active]);
  return <canvas ref={ref} style={{position:"absolute",inset:0,width:"100%",height:"100%",pointerEvents:"none",zIndex:30}}/>;
}

// The real page-turn: uses a CSS clip-path + two canvas halves approach
// Left half stays, right half peels like a real book page
function PageTurnEffect({ fromSrc, toSrc, progress, direction }) {
  // progress: 0 = start, 1 = end
  // The turning page rotates around the spine (left edge for forward, right for backward)
  const p = Math.max(0, Math.min(1, progress));
  
  // Easing
  const ease = p < 0.5 ? 2*p*p : -1+(4-2*p)*p;
  
  if (direction > 0) {
    // Forward: page peels from right to left
    // Current page slides to the left and curls
    const angle = ease * 180; // 0 -> 180 degrees
    const skewAngle = Math.sin(ease * Math.PI) * 18; // bulge in middle
    const scaleX = Math.cos((angle * Math.PI) / 180);
    const shadow = Math.sin(ease * Math.PI);

    return (
      <div style={{ position:"absolute", inset:0, overflow:"hidden" }}>
        {/* Back page (destination) - always visible behind */}
        {toSrc
          ? <img src={toSrc} style={imgStyle} alt="" />
          : <div style={missStyle} />
        }

        {/* Turning page */}
        {p < 1 && (
          <div style={{
            position:"absolute", inset:0,
            transformOrigin: "left center",
            transform: `perspective(1200px) rotateY(${-angle}deg) skewY(${skewAngle * (1 - ease)}deg)`,
            transformStyle: "preserve-3d",
            backfaceVisibility: "hidden",
          }}>
            {/* Front face = current page */}
            <div style={{ position:"absolute", inset:0, backfaceVisibility:"hidden" }}>
              {fromSrc
                ? <img src={fromSrc} style={imgStyle} alt="" />
                : <div style={missStyle} />
              }
              {/* Shadow that grows as page turns */}
              <div style={{
                position:"absolute", inset:0,
                background: `linear-gradient(to right, rgba(0,0,0,${shadow*0.55}), transparent 60%)`,
                pointerEvents:"none",
              }}/>
              {/* Curl highlight on right edge */}
              <div style={{
                position:"absolute", top:0, right:0, bottom:0, width:"8%",
                background: `linear-gradient(to left, rgba(255,255,255,${shadow*0.12}), transparent)`,
                pointerEvents:"none",
              }}/>
            </div>

            {/* Back face = reverse of page (slightly lighter) */}
            <div style={{
              position:"absolute", inset:0,
              backfaceVisibility:"hidden",
              transform:"rotateY(180deg)",
              background:"#f0ece4",
            }}>
              {/* Paper texture lines */}
              {Array.from({length:18},(_,i)=>(
                <div key={i} style={{
                  position:"absolute", left:0, right:0,
                  top: `${(i+1)*5.2}%`, height:1,
                  background:"rgba(0,0,0,0.04)",
                }}/>
              ))}
              <div style={{
                position:"absolute", inset:0,
                background:`linear-gradient(to right, rgba(0,0,0,${(1-ease)*0.3}), transparent 40%)`,
              }}/>
            </div>
          </div>
        )}

        {/* Cast shadow on destination page */}
        {p > 0 && p < 1 && (
          <div style={{
            position:"absolute", inset:0,
            background:`linear-gradient(to right, rgba(0,0,0,${shadow*0.4 * (1-ease)}) 0%, transparent ${30 + ease*40}%)`,
            pointerEvents:"none", zIndex:5,
          }}/>
        )}
      </div>
    );
  } else {
    // Backward: page peels from left to right
    const angle = ease * 180;
    const skewAngle = Math.sin(ease * Math.PI) * 18;
    const shadow = Math.sin(ease * Math.PI);

    return (
      <div style={{ position:"absolute", inset:0, overflow:"hidden" }}>
        {toSrc
          ? <img src={toSrc} style={imgStyle} alt="" />
          : <div style={missStyle} />
        }
        {p < 1 && (
          <div style={{
            position:"absolute", inset:0,
            transformOrigin: "right center",
            transform: `perspective(1200px) rotateY(${angle}deg) skewY(${skewAngle * (1 - ease)}deg)`,
            transformStyle: "preserve-3d",
            backfaceVisibility: "hidden",
          }}>
            <div style={{ position:"absolute", inset:0, backfaceVisibility:"hidden" }}>
              {fromSrc ? <img src={fromSrc} style={imgStyle} alt="" /> : <div style={missStyle}/>}
              <div style={{
                position:"absolute", inset:0,
                background:`linear-gradient(to left, rgba(0,0,0,${shadow*0.55}), transparent 60%)`,
                pointerEvents:"none",
              }}/>
              <div style={{
                position:"absolute", top:0, left:0, bottom:0, width:"8%",
                background:`linear-gradient(to right, rgba(255,255,255,${shadow*0.12}), transparent)`,
                pointerEvents:"none",
              }}/>
            </div>
            <div style={{
              position:"absolute", inset:0,
              backfaceVisibility:"hidden",
              transform:"rotateY(180deg)",
              background:"#f0ece4",
            }}>
              {Array.from({length:18},(_,i)=>(
                <div key={i} style={{
                  position:"absolute", left:0, right:0,
                  top:`${(i+1)*5.2}%`, height:1,
                  background:"rgba(0,0,0,0.04)",
                }}/>
              ))}
              <div style={{
                position:"absolute", inset:0,
                background:`linear-gradient(to left, rgba(0,0,0,${(1-ease)*0.3}), transparent 40%)`,
              }}/>
            </div>
          </div>
        )}
        {p > 0 && p < 1 && (
          <div style={{
            position:"absolute", inset:0,
            background:`linear-gradient(to left, rgba(0,0,0,${shadow*0.4*(1-ease)}) 0%, transparent ${30+ease*40}%)`,
            pointerEvents:"none", zIndex:5,
          }}/>
        )}
      </div>
    );
  }
}

const imgStyle = { width:"100%", height:"100%", objectFit:"cover", display:"block", position:"absolute", inset:0 };
const missStyle = { position:"absolute", inset:0, background:"#111" };

export default function Album() {
  const [page, setPage]       = useState(-1);
  const [flipping, setFlipping] = useState(false);
  const [flipProgress, setFlipProgress] = useState(0);
  const [flipDir, setFlipDir] = useState(1);
  const [fromPage, setFromPage] = useState(-1);
  const [toPage, setToPage]   = useState(0);
  const [confetti, setConfetti] = useState(false);
  const [uploaded, setUploaded] = useState({});
  const rafRef = useRef(null);
  const startRef = useRef(null);
  const DURATION = 680; // ms — real, satisfying page turn

  const getImg = (idx) => {
    if (idx === -1) return IMG.tapa;
    const p = PAGES[idx];
    if (!p) return null;
    return uploaded[p.key] || IMG[p.key] || null;
  };

  const navigate = useCallback((targetPage) => {
    if (flipping) return;
    if (targetPage < -1 || targetPage >= PAGES.length) return;
    const d = targetPage > page ? 1 : -1;
    setFlipDir(d);
    setFromPage(page);
    setToPage(targetPage);
    setFlipping(true);
    setFlipProgress(0);
    startRef.current = null;

    const animate = (ts) => {
      if (!startRef.current) startRef.current = ts;
      const elapsed = ts - startRef.current;
      const prog = Math.min(elapsed / DURATION, 1);
      setFlipProgress(prog);
      if (prog < 1) {
        rafRef.current = requestAnimationFrame(animate);
      } else {
        setPage(targetPage);
        setFlipping(false);
        setFlipProgress(0);
        if (targetPage >= 0 && PAGES[targetPage]?.champ === "Argentina") {
          setConfetti(true);
          setTimeout(() => setConfetti(false), 2800);
        }
      }
    };
    rafRef.current = requestAnimationFrame(animate);
  }, [flipping, page]);

  useEffect(() => () => cancelAnimationFrame(rafRef.current), []);

  const upload = (key, file) => {
    if (!file) return;
    const r = new FileReader();
    r.onload = e => setUploaded(p => ({...p, [key]: e.target.result}));
    r.readAsDataURL(file);
  };

  const currPage = page >= 0 ? PAGES[page] : null;
  const accentColor = currPage ? currPage.color : "#f0c040";

  // What to show when not flipping
  const currentImg = getImg(page);

  return (
    <div style={s.root}>
      {/* Ambient glow */}
      <div style={{
        ...s.bgGlow,
        background:`radial-gradient(ellipse 65% 50% at 50% 40%, ${accentColor}16 0%, transparent 70%)`,
        transition:"background 1.2s ease",
      }}/>

      {/* BOOK */}
      <div style={s.bookWrap}>
        {/* Page area */}
        <div style={s.pageArea}>
          {flipping ? (
            <PageTurnEffect
              fromSrc={getImg(fromPage)}
              toSrc={getImg(toPage)}
              progress={flipProgress}
              direction={flipDir}
            />
          ) : (
            <div style={{position:"absolute",inset:0}}>
              {currentImg
                ? <img src={currentImg} style={{...imgStyle, position:"absolute"}} alt="" />
                : (
                  <div style={s.missing}>
                    <span style={{...s.missYear, color:`${accentColor}44`}}>{currPage?.year}</span>
                    <span style={s.missHost}>{currPage?.host}</span>
                    <span style={s.missHint}>Lámina pendiente</span>
                    <label style={{...s.uploadBtn, background:accentColor, color:"#111"}}>
                      + Subir lámina
                      <input type="file" accept="image/*" style={{display:"none"}}
                        onChange={e=>currPage&&upload(currPage.key,e.target.files[0])}/>
                    </label>
                  </div>
                )
              }
              {/* Vignette */}
              <div style={s.vignette}/>
              {/* Replace button */}
              {currentImg && page !== -1 && (
                <label style={s.replaceBtn}>🔄
                  <input type="file" accept="image/*" style={{display:"none"}}
                    onChange={e=>currPage&&upload(currPage.key,e.target.files[0])}/>
                </label>
              )}
              {/* Confetti */}
              <Confetti active={confetti} />
            </div>
          )}

          {/* Subtle left spine crease */}
          <div style={s.spineInner}/>
        </div>

        {/* Drop shadow underneath book */}
        <div style={s.bookShadow}/>
      </div>

      {/* Info bar */}
      <div style={{...s.strip, borderColor:`${accentColor}35`}}>
        <div style={{...s.dot0, background:accentColor, boxShadow:`0 0 8px ${accentColor}`}}/>
        <span style={s.stripText}>
          {page===-1 ? "⚽ Mundiales de Fútbol · Samir Muhana · 5°B"
            : `${currPage?.year} · ${currPage?.host} · ${currPage?.flag} ${currPage?.champ}`}
        </span>
        <span style={s.stripCount}>{page===-1?"Tapa":`${page+1} / ${PAGES.length}`}</span>
      </div>

      {/* Nav */}
      <div style={s.nav}>
        <button style={{...s.navBtn, opacity:page<=-1||flipping?0.2:1}}
          onClick={()=>navigate(page-1)} disabled={page<=-1||flipping}>‹</button>

        <div style={s.dots}>
          {[-1,...PAGES.map((_,i)=>i)].map(i=>{
            const active=page===i;
            const col=i===-1?"#f0c040":PAGES[i].color;
            return <button key={i} onClick={()=>!flipping&&navigate(i)} style={{
              ...s.dotBtn,
              width:active?26:7, height:7,
              background:active?col:"rgba(255,255,255,0.18)",
              boxShadow:active?`0 0 8px ${col}`:"none",
            }} title={i===-1?"Tapa":String(PAGES[i].year)}/>;
          })}
        </div>

        <button style={{...s.navBtn, opacity:page>=PAGES.length-1||flipping?0.2:1}}
          onClick={()=>navigate(page+1)} disabled={page>=PAGES.length-1||flipping}>›</button>
      </div>

      <style>{`
        *{box-sizing:border-box;margin:0;padding:0;}
        button{border:none;cursor:pointer;background:transparent;}
      `}</style>
    </div>
  );
}

const s = {
  root:{
    minHeight:"100vh", background:"#0c0c0c",
    display:"flex", flexDirection:"column",
    alignItems:"center", justifyContent:"center",
    gap:18, padding:"20px 80px",
    fontFamily:"system-ui,-apple-system,sans-serif",
    position:"relative", overflow:"hidden", userSelect:"none",
  },
  bgGlow:{position:"absolute",inset:"-20%",pointerEvents:"none",zIndex:0},
  bookWrap:{
    position:"relative", width:"100%", maxWidth:490, zIndex:1,
    filter:"drop-shadow(0 50px 100px rgba(0,0,0,0.95)) drop-shadow(0 15px 30px rgba(0,0,0,0.7))",
  },
  pageArea:{
    aspectRatio:"3/4",
    borderRadius:8,
    overflow:"hidden", position:"relative",
    background:"#1a1a1a",
  },
  spineInner:{
    position:"absolute",left:0,top:0,bottom:0,width:10,
    background:"linear-gradient(to right,rgba(0,0,0,0.28),transparent)",
    pointerEvents:"none",zIndex:20,
  },
  bookShadow:{
    position:"absolute", bottom:-30, left:"5%", right:"5%", height:40,
    background:"radial-gradient(ellipse at center, rgba(0,0,0,0.7) 0%, transparent 70%)",
    filter:"blur(15px)", pointerEvents:"none",
  },
  vignette:{
    position:"absolute",inset:0,
    background:"radial-gradient(ellipse at center, transparent 55%, rgba(0,0,0,0.4) 100%)",
    pointerEvents:"none",zIndex:10,
  },
  replaceBtn:{
    position:"absolute",top:10,right:10,zIndex:15,
    background:"rgba(0,0,0,0.55)",backdropFilter:"blur(10px)",
    border:"1px solid rgba(255,255,255,0.15)",
    borderRadius:8,padding:"6px 10px",cursor:"pointer",fontSize:15,color:"#fff",
  },
  missing:{
    width:"100%",height:"100%",display:"flex",flexDirection:"column",
    alignItems:"center",justifyContent:"center",background:"#0e0e0e",gap:10,
  },
  missYear:{fontSize:76,fontWeight:900,lineHeight:1,letterSpacing:-3},
  missHost:{fontSize:16,color:"rgba(255,255,255,0.3)",fontWeight:500},
  missHint:{fontSize:11,color:"rgba(255,255,255,0.15)",letterSpacing:2,textTransform:"uppercase"},
  uploadBtn:{marginTop:14,border:"none",padding:"11px 26px",borderRadius:10,cursor:"pointer",fontWeight:700,fontSize:13},
  strip:{
    display:"flex",alignItems:"center",gap:10,
    width:"100%",maxWidth:490,zIndex:1,
    background:"rgba(255,255,255,0.03)",
    border:"1px solid",borderRadius:10,padding:"9px 14px",
    backdropFilter:"blur(12px)",
  },
  dot0:{width:8,height:8,borderRadius:"50%",flexShrink:0,transition:"background 0.6s,box-shadow 0.6s"},
  stripText:{flex:1,fontSize:13,color:"rgba(255,255,255,0.6)",fontWeight:500,letterSpacing:0.3},
  stripCount:{fontSize:11,color:"rgba(255,255,255,0.2)",fontFamily:"monospace",letterSpacing:1},
  nav:{display:"flex",alignItems:"center",width:"100%",maxWidth:490,gap:14,zIndex:1},
  navBtn:{
    width:44,height:44,borderRadius:10,fontSize:26,color:"#fff",
    background:"rgba(255,255,255,0.06)",border:"1px solid rgba(255,255,255,0.1)",
    backdropFilter:"blur(10px)",transition:"opacity 0.2s",flexShrink:0,
    display:"flex",alignItems:"center",justifyContent:"center",
  },
  dots:{display:"flex",alignItems:"center",gap:5,flex:1,flexWrap:"wrap",justifyContent:"center"},
  dotBtn:{
    borderRadius:4,border:"none",cursor:"pointer",padding:0,flexShrink:0,
    transition:"width 0.3s cubic-bezier(0.4,0,0.2,1),background 0.3s,box-shadow 0.3s",
  },
};
